import{_ as e,c as l,o as i,aQ as r}from"./chunks/framework.Ddvqt8dM.js";const L=JSON.parse('{"title":"大语言模型（LLM）入门指南","description":"","frontmatter":{"title":"大语言模型（LLM）入门指南","date":"2025-11-20T16:00:00.000Z","tags":["AI","LLM","机器学习"],"categories":["AI 技术"],"coverImg":"/img/cover/llm_learning_bg_1.png","permalink":"/ai-learning/"},"headers":[],"relativePath":"20.AI 学习与实践/index.md","filePath":"20.AI 学习与实践/index.md"}'),n={name:"20.AI 学习与实践/index.md"};function t(o,a,d,s,h,m){return i(),l("div",null,[...a[0]||(a[0]=[r('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /20.AI 学习与实践.md for this page in Markdown format</div><h1 id="大语言模型-llm-入门指南" tabindex="-1">大语言模型（LLM）入门指南 <a class="header-anchor" href="#大语言模型-llm-入门指南" aria-label="Permalink to “大语言模型（LLM）入门指南”">​</a></h1><p>大语言模型（Large Language Models，简称 LLM）是人工智能领域的重要突破，它们能够理解和生成人类语言。</p><h2 id="什么是大语言模型" tabindex="-1">什么是大语言模型？ <a class="header-anchor" href="#什么是大语言模型" aria-label="Permalink to “什么是大语言模型？”">​</a></h2><p>大语言模型是基于深度学习的模型，通过训练大量文本数据来学习语言的模式和结构。它们可以完成多种自然语言处理任务，如文本生成、翻译、问答等。</p><h2 id="llm-的工作原理" tabindex="-1">LLM 的工作原理 <a class="header-anchor" href="#llm-的工作原理" aria-label="Permalink to “LLM 的工作原理”">​</a></h2><ol><li><strong>训练阶段</strong>：使用海量文本数据进行预训练</li><li><strong>微调阶段</strong>：针对特定任务进行调整</li><li><strong>推理阶段</strong>：处理用户输入并生成响应</li></ol><h2 id="常见的-llm" tabindex="-1">常见的 LLM <a class="header-anchor" href="#常见的-llm" aria-label="Permalink to “常见的 LLM”">​</a></h2><ul><li>GPT 系列（OpenAI）</li><li>Gemini（Google）</li><li>Claude（Anthropic）</li><li>Llama（Meta）</li><li>Qwen（阿里）</li></ul><h2 id="应用场景" tabindex="-1">应用场景 <a class="header-anchor" href="#应用场景" aria-label="Permalink to “应用场景”">​</a></h2><ul><li>内容生成</li><li>代码辅助</li><li>教育辅导</li><li>智能客服</li><li>数据分析</li></ul><p>大语言模型正在改变我们与技术交互的方式，未来将有更多创新应用出现。</p>',12)])])}const p=e(n,[["render",t]]);export{L as __pageData,p as default};
